fn getPattern(data: LogData, side: Neighbor) Pattern {
	if (data.isConnected(side)) {
		return .cut;
	}

	const pattern = branch.getPattern(data, side).?;

	switch (pattern) {
		.dot => {
			return .dot;
		},
		.halfLine => |dir| {
			return .{.line = .fromBranchDirection(dir)};
		},
		.line => |dir| {
			return .{.line = .fromBranchDirection(dir)};
		},
		.bend => |dir| {
			return .{.bend = dir};
		},
		.intersection => |dir| {
			return .{.intersection = dir};
		},
		.cross => {
			return .cross;
		},
	}
}

